import { createStore } from "redux"

const initialState = {
 form: {}
}

function reducer(state = initialState, action){

 if(action.type === "UPDATE_FORM"){
  return {
   ...state,
   form:{...state.form, ...action.payload}
  }
 }

 return state
}

export const store = createStore(reducer)
